def fib(n):
    if n <= 1:
        return n
    return fib(n - 1) + fib(n - 2)

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

def is_palindrome_num(n):
    s = str(n)
    return s == s[::-1]

def gcd_of(a, b):
    while b:
        a, b = b, a % b
    return a
